import{_ as e,c as r,q as a,o as l}from"./chunks/framework.CgQGrdLP.js";const n="/assets/bandage.DcaPlDNd.png",u=JSON.parse('{"title":"新春启航｜启航计划（马年新春版）正式结营！","description":"","frontmatter":{"title":"新春启航｜启航计划（马年新春版）正式结营！","date":"2026-03-19T00:00:00.000Z","author":{"name":"孙钟恺","github":"sunzhongkai588"},"category":"community-activity"},"headers":[],"relativePath":"posts/starter-horse-year.md","filePath":"posts/starter-horse-year.md"}'),o={name:"posts/starter-horse-year.md"};function s(g,t,i,d,h,f){return l(),r("div",null,[...t[0]||(t[0]=[a('<p>在 <strong>2026 年 1 月 26 日</strong>，飞桨开源社区正式启动了 <strong>「启航计划」马年新春版</strong> —— 一场为寒假与春节假期特别推出的限时开源集训。经过为期 <strong>1 个月</strong>快节奏的线上集训，活动已于 <strong>3 月 9 日</strong> 顺利完成全部计划，正式圆满结营 🎉。</p><p>本期启航计划是一次围绕 <strong>新春假期</strong> 量身打造的特别版集训，横跨春节假期，节奏更快、体验更集中。我们希望在年初相对集中的空闲时间里，为对开源感兴趣的开发者提供一个 <strong>低门槛、可实践</strong> 的参与机会——让大家在新的一年，迈出属于自己的 <strong>第一步开源实践</strong>。</p><p>在集训过程中，大部分营员均完成了 <strong>三项热身打卡任务</strong>（文档修复、Paddle 本地编译、FastDeploy 本地编译），并逐步熟悉了飞桨开源社区的协作方式与贡献流程。最终，共有 <strong>17 位营员</strong> 在热身打卡任务之外，成功向飞桨开源仓库合入了 PR，完成了从&quot;学习者&quot;到&quot;贡献者&quot;的关键一步，达到结营要求并顺利结营。<strong>衷心感谢每一位营员在启航计划中的投入与坚持</strong>，你们的每一次 PR 修改、每一次 issue 讨论，都是飞桨开源生态持续演进的重要组成部分。</p><blockquote><p>目前所有结营名单已经公示，详情见：<a href="https://github.com/PFCCLab/Starter/issues/867" target="_blank" rel="noreferrer">「启航计划」马年新春版 结营考核公示</a></p></blockquote><h2 id="优秀营员" tabindex="-1">优秀营员 <a class="header-anchor" href="#优秀营员" aria-label="Permalink to &quot;优秀营员&quot;">​</a></h2><p>与正常「启航计划」不同，马年新春版<strong>不设一、二、三等奖答辩流程</strong>，专注任务完成与成果产出。我们从贡献质量、开源参与度、技术深度等多个维度进行综合评估，最终评选出 <strong>6 位优秀营员</strong>：</p><table tabindex="0"><thead><tr><th style="text-align:left;">优秀营员</th><th style="text-align:left;">亮点</th></tr></thead><tbody><tr><td style="text-align:left;"><a href="https://github.com/Aidenwu0209" target="_blank" rel="noreferrer">@Aidenwu0209</a></td><td style="text-align:left;">合入 12 个非热身 PR；首创 PaddleOCR 官方 Claude Code Skill（文本识别 + 文档解析），从 0 到 1 开发全新任务形态；API 兼容性任务覆盖 10+ 子项，跨 Paddle / docs / PaConvert / PaddleOCR 4 个仓库</td></tr><tr><td style="text-align:left;"><a href="https://github.com/tjujingzong" target="_blank" rel="noreferrer">@tjujingzong</a></td><td style="text-align:left;">合入 13 个非热身 PR（全营最多）；攻克高难度 XPU 0-size tensor 系列 PR，需深入理解 XPU kernel 与 GPU 行为差异；任务覆盖 CUDA Kernel、XPU、单测修复、API 兼容性等多个方向</td></tr><tr><td style="text-align:left;"><a href="https://github.com/Khoray" target="_blank" rel="noreferrer">@Khoray</a></td><td style="text-align:left;">合入 3 个 API 兼容性 PR（全栈完成）；独立设计并开发了一套多媒体 OCR 搜索工具（FastAPI + PaddleOCR + Milvus 向量检索，端到端完成）</td></tr><tr><td style="text-align:left;"><a href="https://github.com/gravel-01" target="_blank" rel="noreferrer">@gravel-01</a></td><td style="text-align:left;">深耕 PaddleOCR error_correction 项目核心开发（图像预处理模块，合入 4 个 PR）；撰写并发布图像预处理最佳实践 Blog；使用 OmniDocBench 数据集训练图像分类器</td></tr><tr><td style="text-align:left;"><a href="https://github.com/HZ1ovo" target="_blank" rel="noreferrer">@HZ1ovo</a></td><td style="text-align:left;">发起文档链接修复任务 <a href="https://github.com/PaddlePaddle/docs/issues/7735" target="_blank" rel="noreferrer">issue #7735</a>，拆分为 126 个子任务供全营参与；积极参与 issue 管理与 PR review，协助其他营员解决问题</td></tr><tr><td style="text-align:left;"><a href="https://github.com/MerlinSMQWQ" target="_blank" rel="noreferrer">@MerlinSMQWQ</a></td><td style="text-align:left;">合入 3 个 API 兼容性 PR；沉淀编译排错文档帮助其他营员；与 <a href="https://github.com/OctoberPrayRain" target="_blank" rel="noreferrer">@OctoberPrayRain</a> 协作开发 RainyOCR 屏幕文字 OCR 项目</td></tr></tbody></table><p>优秀营员将进入 <strong>「护航计划」候选池</strong>，并获得 <strong>马年飞桨开源社区特别徽章</strong>。</p><div style="display:flex;justify-content:center;"><figure style="width:50%;"><img src="'+n+'" alt="bandage"><figcaption>马年飞桨开源社区特别徽章设计图</figcaption></figure></div><h2 id="周密的活动安排" tabindex="-1">周密的活动安排 <a class="header-anchor" href="#周密的活动安排" aria-label="Permalink to &quot;周密的活动安排&quot;">​</a></h2><p>本期启航计划线上集训营为期 <strong>1 个月</strong>（横跨春节期间），以双周周报的形式进行阶段性汇报总结。整体安排如下，未参与过启航计划的同学也欢迎参考了解：</p><table tabindex="0"><thead><tr><th style="text-align:left;"><strong>时间</strong></th><th style="text-align:left;"><strong>日程</strong></th></tr></thead><tbody><tr><td style="text-align:left;"><strong>2026.1.26</strong></td><td style="text-align:left;">正式启动报名</td></tr><tr><td style="text-align:left;"><strong>2026.1.26 ~ 2026.2.5</strong></td><td style="text-align:left;">持续公开接收简历，确定营员名单</td></tr><tr><td style="text-align:left;"><strong>2026.2.6 19:00</strong></td><td style="text-align:left;">集训项目启动</td></tr><tr><td style="text-align:left;"><strong>2026.2.6 ～ 2026.3.9</strong></td><td style="text-align:left;">参与集训项目（4 weeks）</td></tr><tr><td style="text-align:left;"><strong>2026.3.9 23:59</strong></td><td style="text-align:left;">集训营结营，公布考核结果</td></tr></tbody></table><p>在集训期间，我们通过<strong>双周周报</strong>持续跟进营员的开发进度，帮助大家在阶段性总结中及时查缺补漏。未按时提交周报的营员，将被视为自动退出集训营。</p><table tabindex="0"><thead><tr><th style="text-align:left;"><strong>时间</strong></th><th style="text-align:left;"><strong>日程</strong></th><th style="text-align:left;"><strong>提交情况</strong></th></tr></thead><tbody><tr><td style="text-align:left;"><strong>2026.2.22</strong></td><td style="text-align:left;"><a href="https://github.com/PFCCLab/Starter/issues/812" target="_blank" rel="noreferrer">第一次周报收集</a></td><td style="text-align:left;"><strong>24 / 31</strong> 人提交（提交率 <strong>77.4%</strong>）</td></tr><tr><td style="text-align:left;"><strong>2026.3.9</strong></td><td style="text-align:left;"><a href="https://github.com/PFCCLab/Starter/issues/841" target="_blank" rel="noreferrer">第二次周报收集</a></td><td style="text-align:left;"><strong>21 / 24</strong> 人提交（提交率 <strong>87.5%</strong>）</td></tr></tbody></table><p>本期集训的任务方向涵盖多个技术领域：</p><table tabindex="0"><thead><tr><th style="text-align:left;"><strong>开源贡献 repo</strong></th><th style="text-align:left;"><strong>任务方向</strong></th><th style="text-align:left;"><strong>导师</strong></th></tr></thead><tbody><tr><td style="text-align:left;">PaddleMaterials</td><td style="text-align:left;">数据集适配</td><td style="text-align:left;"><a href="https://github.com/leeleolay" target="_blank" rel="noreferrer">@leeleolay</a></td></tr><tr><td style="text-align:left;">GraphNet</td><td style="text-align:left;">计算图收集</td><td style="text-align:left;"><a href="https://github.com/JewelRoam" target="_blank" rel="noreferrer">@JewelRoam</a></td></tr><tr><td style="text-align:left;">Paddle / PaConvert / docs</td><td style="text-align:left;">API 兼容性增强</td><td style="text-align:left;"><a href="https://github.com/zhwesky2010" target="_blank" rel="noreferrer">@zhwesky2010</a></td></tr><tr><td style="text-align:left;">PaddleOCR</td><td style="text-align:left;">PaddleOCR + ERNIE 高价值开源项目案例征集</td><td style="text-align:left;"><a href="https://github.com/openvino-book" target="_blank" rel="noreferrer">@openvino-book</a></td></tr></tbody></table><h2 id="一些成果" tabindex="-1">一些成果 <a class="header-anchor" href="#一些成果" aria-label="Permalink to &quot;一些成果&quot;">​</a></h2><p>本期马年新春版启航计划吸引了来自不同学校、不同背景的 <strong>31 位开发者</strong> 报名参与，虽然开发周期仅有短短一个月，但大家用实际行动交出了一份令人欣喜的答卷。</p><p><strong>数字上的成果：</strong></p><ul><li><strong>31 位营员</strong> 报名参与 → <strong>24 位</strong> 提交首次周报 → <strong>21 位</strong> 坚持到第二次周报 → <strong>17 位</strong> 满足结营要求并顺利通过考核，其中 <strong>6 位</strong> 被评为优秀营员</li><li>全体结营营员累计向飞桨相关开源仓库合入 <strong>86 个</strong> PR，贡献覆盖 <strong>Paddle、docs、PaConvert、PaddleOCR、GraphNet、FastDeploy</strong> 等多个核心仓库</li><li>贡献最活跃的营员 <a href="https://github.com/Aidenwu0209" target="_blank" rel="noreferrer">@Aidenwu0209</a> 合入了 <strong>22 个</strong> PR，<a href="https://github.com/tjujingzong" target="_blank" rel="noreferrer">@tjujingzong</a> 合入了 <strong>18 个</strong> PR</li><li><a href="https://github.com/HZ1ovo" target="_blank" rel="noreferrer">@HZ1ovo</a> 发起的文档链接修复 <a href="https://github.com/PaddlePaddle/docs/issues/7735" target="_blank" rel="noreferrer">issue #7735</a> 拆分为 <strong>126 个子任务</strong>，带动多位营员共同参与</li></ul><h2 id="最后" tabindex="-1">最后 <a class="header-anchor" href="#最后" aria-label="Permalink to &quot;最后&quot;">​</a></h2><p>🎉恭喜以下所有顺利通过结营考核的营员！你们用实际行动完成了挑战，在这个新春假期为飞桨开源社区写下了浓墨重彩的一笔：<a href="https://github.com/Aidenwu0209" target="_blank" rel="noreferrer">@Aidenwu0209</a>、<a href="https://github.com/tjujingzong" target="_blank" rel="noreferrer">@tjujingzong</a>、<a href="https://github.com/Khoray" target="_blank" rel="noreferrer">@Khoray</a>、<a href="https://github.com/MerlinSMQWQ" target="_blank" rel="noreferrer">@MerlinSMQWQ</a>、<a href="https://github.com/SidusAntares" target="_blank" rel="noreferrer">@SidusAntares</a>、<a href="https://github.com/HZ1ovo" target="_blank" rel="noreferrer">@HZ1ovo</a>、<a href="https://github.com/BayesianAura" target="_blank" rel="noreferrer">@BayesianAura</a>、<a href="https://github.com/Carousel126" target="_blank" rel="noreferrer">@Carousel126</a>、<a href="https://github.com/chengchen512" target="_blank" rel="noreferrer">@chengchen512</a>、<a href="https://github.com/darkerkiller" target="_blank" rel="noreferrer">@darkerkiller</a>、<a href="https://github.com/lywlyw2004" target="_blank" rel="noreferrer">@lywlyw2004</a>、<a href="https://github.com/cvbret" target="_blank" rel="noreferrer">@cvbret</a>、<a href="https://github.com/gravel-01" target="_blank" rel="noreferrer">@gravel-01</a>、<a href="https://github.com/aotenjou" target="_blank" rel="noreferrer">@aotenjou</a>、<a href="https://github.com/Chloris-001" target="_blank" rel="noreferrer">@Chloris-001</a>、<a href="https://github.com/inaniloquentee" target="_blank" rel="noreferrer">@inaniloquentee</a>、<a href="https://github.com/OctoberPrayRain" target="_blank" rel="noreferrer">@OctoberPrayRain</a></p><p>同时，也感谢所有报名并参与其中的同学。即使有部分营员因时间或其他原因未能通过本次考核，我们依然由衷感谢你们的投入与尝试，期待未来在飞桨或其他开源社区中再次见到你们的身影。之后可以关注 <a href="https://github.com/orgs/PaddlePaddle/projects/7" target="_blank" rel="noreferrer">https://github.com/orgs/PaddlePaddle/projects/7</a> ，会不定期更新新的开源任务，参与即能锻炼技能，还有机会赢取开源小礼品～ 🏆</p><p>所以，下一期的启航计划，你心动了吗？💓</p>',24)])])}const p=e(o,[["render",s]]);export{u as __pageData,p as default};
